import * as React from "react";

export interface ClaimIntakeStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
}

const FIELDS: ReadonlyArray<{ id: string; label: string; required: boolean; pii: boolean }> = [
	{ id: "claimant_name", label: "Claimant full name", required: true, pii: true },
	{ id: "policy_number", label: "Policy number", required: true, pii: false },
	{ id: "loss_date", label: "Date of loss", required: true, pii: false },
	{ id: "loss_amount", label: "Estimated loss amount", required: true, pii: false },
	{ id: "loss_description", label: "Description of loss", required: true, pii: false },
	{ id: "contact_email", label: "Contact email", required: true, pii: true },
	{ id: "contact_phone", label: "Contact phone", required: false, pii: true },
];

/**
 * Minimal review step for the claim_intake workflow. Hosts wrap this with
 * the project-wide auth/tenant context — keeping the component dumb so
 * generated code stays portable across Next.js and plain Vite apps.
 */
export function ClaimIntakeStep(props: ClaimIntakeStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);

	const fire = React.useCallback(
		async (event: string) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, {});
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	return (
		<section data-testid="claim_intake-step" aria-labelledby="claim_intake-step-title">
			<header>
				<h2 id="claim_intake-step-title">File an insurance claim (FNOL)</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<dl>
				{FIELDS.map((field) => (
					<React.Fragment key={field.id}>
						<dt>{field.label}{field.required ? " *" : ""}{field.pii ? " (PII)" : ""}</dt>
						<dd>—</dd>
					</React.Fragment>
				))}
			</dl>
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("submit")}>
					Submit
				</button>
				<button type="button" disabled={busy} onClick={() => fire("approve")}>
					Approve
				</button>
			</footer>
		</section>
	);
}
